/** Countries whose airports fall in any of the given cell keys (`floor(lng),floor(lat)`). */
export function countriesForCellKeys(cellKeys) {
  const countries = new Set();
  for (const cellKey of cellKeys) {
    const list = CELL_COUNTRIES[cellKey];
    if (!list) {
      continue;
    }
    for (const cc of list) {
      countries.add(cc);
    }
  }
  return [...countries].sort();
}
